from rq import Queue
from redis import Redis

redis = Redis(host="redis", port=6379)
queue = Queue("geo-processing", connection=redis)

def process_upload(upload_id: str):
    # 1. file storage'dan faylni ol
    # 2. GDAL/GeoPandas bilan tozala
    # 3. PostGIS'ga yoz
    # 4. statusni accepted/failed qilib yangila
    return {"upload_id": upload_id, "status": "done"}

def enqueue_upload(upload_id: str):
    job = queue.enqueue(process_upload, upload_id)
    return {"job_id": job.id, "status": "queued"}

